#include<bits/stdc++.h>
using namespace std;
long long a[1000005],n,maxn=0;
bool cmp(long long x,long long y){
    return x>y;
}
int main(void){
	scanf("%lld",&n);
	for(long long i=0;i<n;i++)scanf("%lld",&a[i]);
    sort(a,a+n,cmp);n=min(n,1ll*32);
	for(long long i=0;i<n;i++){
		for(long long j=i+1;j<n;j++){
			maxn=max(maxn,a[i]&a[j]);
		}
	}
    printf("%lld",maxn);
	return false;
}
